def is_nested(string):
    balance = 0
    has_nested = False
    for char in string:
        if char == '[':
            balance += 1
        elif char == ']':
            balance -= 1
            if balance > 0:
                has_nested = True
        if balance < 0:
            return False
    return has_nested and balance == 0
